PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?race ?winner ?poleDriver WHERE {
  ?race wdt:P361 wd:Q4600101 ; wdt:P1344 ?winner ; wdt:P3764 ?poleDriver .
  ?winner wdt:P19 wd:Q202560
}

args.sparql:
SELECT ?race ?winner WHERE { 
  wd:Q4600101 wdt:P361 ?race . 
  ?race wdt:P1344 ?winner . 
  ?winner wdt:P19 wd:Q202560 .
}

SELECT ?race ?winner ?poleDriver WHERE { 
  ?race wdt:P3450 wd:Q4600101 .
  ?race wdt:P3971 ?winner .
  ?winner wdt:P19 wd:Q202560 .
  ?race wdt:P3764 ?poleDriver .
}

SELECT ?race ?winner WHERE { 
  ?race wdt:P710 wd:Q4600101 . 
  ?race wdt:P1344 ?winner .
  ?winner wdt:P19 wd:Q202560 .
}

SELECT ?race ?winner ?birthplace WHERE { 
  { ?race wdt:P361 wd:Q4600101 } 
  UNION { ?race wdt:P3450 wd:Q4600101 } 
  UNION { ?race wdt:P710 wd:Q4600101 } 
  ?race wdt:P1344 ?winner .
  ?winner wdt:P19 ?birthplace .
}

SELECT ?race ?raceLabel WHERE { 
  ?race wdt:P3450 wd:Q4600101 ; 
        wdt:P1353 ?winner .
  ?winner wdt:P19 wd:Q202560 .
  ?race rdfs:label ?raceLabel .
  FILTER(LANG(?raceLabel) = 'en')
}
